import React, { useEffect, useState } from "react";

import {
  getTransactions,
  createTransaction,
  reverseTransaction,
} from "../api/transactions";

import { getWallets } from "../api/wallets";
import { getCategories } from "../api/categories";

import "../styles/Layouts.css";

function Transactions() {
  const [transactions, setTransactions] = useState([]);
  const [wallets, setWallets] = useState([]);
  const [categories, setCategories] = useState([]);

  const [form, setForm] = useState({
    wallet_id: "",
    category_id: "",
    amount: "",
    transaction_type: "Expense",
    description: "",
  });

  const loadData = async () => {
    try {
      const [txRes, walletRes, categoryRes] =
        await Promise.all([
          getTransactions(),
          getWallets(),
          getCategories(),
        ]);

      setTransactions(txRes.data.data);
      setWallets(walletRes.data);
      setCategories(categoryRes.data.data);
    } catch {
      alert("Không tải được dữ liệu");
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleCreate = async () => {
    try {
      await createTransaction(form);

      setForm({
        wallet_id: "",
        category_id: "",
        amount: "",
        transaction_type: "Expense",
        description: "",
      });

      loadData();
    } catch (err) {
      alert(
        err?.response?.data?.message ||
          "Không thể tạo giao dịch"
      );
    }
  };

  const handleReverse = async (id) => {
    try {
      await reverseTransaction(id);
      loadData();
    } catch (err) {
      alert(
        err?.response?.data?.message ||
          "Không thể reverse giao dịch"
      );
    }
  };

  return (
    <div className="main-content">

      <div className="page-header">
        <h1 className="page-title">
          Giao dịch
        </h1>

        <p className="page-subtitle">
          Quản lý thu chi cá nhân
        </p>
      </div>

      {/* FORM */}

      <div className="card">
        <h2 className="card-title">
          Thêm giao dịch
        </h2>

        <div
          style={{
            display: "grid",
            gridTemplateColumns:
              "repeat(auto-fit,minmax(220px,1fr))",
            gap: "12px",
          }}
        >
          <select
            value={form.wallet_id}
            onChange={(e) =>
              setForm({
                ...form,
                wallet_id: e.target.value,
              })
            }
          >
            <option value="">
              Chọn ví
            </option>

            {wallets.map((w) => (
              <option
                key={w.wallet_id}
                value={w.wallet_id}
              >
                {w.wallet_name}
              </option>
            ))}
          </select>

          <select
            value={form.category_id}
            onChange={(e) =>
              setForm({
                ...form,
                category_id: e.target.value,
              })
            }
          >
            <option value="">
              Chọn danh mục
            </option>

            {categories.map((c) => (
              <option
                key={c.category_id}
                value={c.category_id}
              >
                {c.category_name}
              </option>
            ))}
          </select>

          <select
            value={form.transaction_type}
            onChange={(e) =>
              setForm({
                ...form,
                transaction_type:
                  e.target.value,
              })
            }
          >
            <option value="Expense">
              Expense
            </option>

            <option value="Income">
              Income
            </option>
          </select>

          <input
            type="number"
            placeholder="Số tiền"
            value={form.amount}
            onChange={(e) =>
              setForm({
                ...form,
                amount: e.target.value,
              })
            }
          />

          <input
            type="text"
            placeholder="Mô tả"
            value={form.description}
            onChange={(e) =>
              setForm({
                ...form,
                description: e.target.value,
              })
            }
          />

          <button
            className="btn btn-primary"
            onClick={handleCreate}
          >
            Thêm giao dịch
          </button>
        </div>
      </div>

      {/* LIST */}

      <div className="card">
        <h2 className="card-title">
          Danh sách giao dịch
        </h2>

        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
          }}
        >
          <thead>
            <tr>
              <th>Mô tả</th>
              <th>Loại</th>
              <th>Số tiền</th>
              <th>Thao tác</th>
            </tr>
          </thead>

          <tbody>
            {transactions.map((t) => (
              <tr key={t.transaction_id}>
                <td>{t.description}</td>

                <td>
                  {t.transaction_type}
                </td>

                <td>
                  {Number(
                    t.amount || 0
                  ).toLocaleString()}{" "}
                  VNĐ
                </td>

                <td>
                  <button
                    className="btn btn-danger"
                    onClick={() =>
                      handleReverse(
                        t.transaction_id
                      )
                    }
                  >
                    Reverse
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

      </div>

    </div>
  );
}

export default Transactions;
